import{_ as r,o as t,c as a,ag as i}from"./chunks/framework.Ba7HPom2.js";const _=JSON.parse('{"title":"Android四大组件学习","description":"","frontmatter":{"title":"Android四大组件学习","date":"2019-09-19T00:00:00.000Z","description":"","tags":["Android"],"categories":["Android"]},"headers":[],"relativePath":"posts/23-Android四大组件学习.md","filePath":"posts/23-Android四大组件学习.md","lastUpdated":null}'),o={name:"posts/23-Android四大组件学习.md"};function d(n,e,s,c,l,p){return t(),a("div",null,[...e[0]||(e[0]=[i('<blockquote><p>这篇博文是从本人过去的 github pages 博客迁移过来，时间上会比较古老。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>Android 四大组件包括：</p><ul><li>Activity</li><li>Serivce</li><li>Content Provider</li><li>Broadcast receiver</li></ul><p>从四大组件来看，Google 把应用抽象成了<strong>UI 逻辑</strong>、<strong>后台逻辑</strong>、<strong>持久化</strong>和<strong>应用间通讯</strong>四个部分。</p><h2 id="activity" tabindex="-1">Activity <a class="header-anchor" href="#activity" aria-label="Permalink to &quot;Activity&quot;">​</a></h2><p>Activity 就是用户最能直观感受到的一个部分，负责 UI 的显示和 UI 的逻辑。</p><h2 id="serivce" tabindex="-1">Serivce <a class="header-anchor" href="#serivce" aria-label="Permalink to &quot;Serivce&quot;">​</a></h2><p>为了不阻塞前台 UI 的显示，应用大部分的后台逻辑都应该放到 Serivce 部分。</p><h2 id="content-provider" tabindex="-1">Content Provider <a class="header-anchor" href="#content-provider" aria-label="Permalink to &quot;Content Provider&quot;">​</a></h2><p>Provider 是一种简化的数据持久层，可以被多个应用访问。</p><h2 id="broadcast-receiver" tabindex="-1">Broadcast receiver <a class="header-anchor" href="#broadcast-receiver" aria-label="Permalink to &quot;Broadcast receiver&quot;">​</a></h2><p>Broadcast receiver 是广播的接受者，可以接受系统广播，也可以接受指定应用的自定义广播。</p><p>广播是一种简单的进程间通讯的方式。</p>',14)])])}const v=r(o,[["render",d]]);export{_ as __pageData,v as default};
